import{_ as a,o as t,c as o,a4 as r}from"./chunks/framework.DZgsdRSv.js";const m=JSON.parse('{"title":"About labs","description":"This page gives on overview of lab management in HUNT Cloud.","frontmatter":{"title":"About labs","category":"HUNT Cloud","permalink":"/administer-science/start-here/labs","outline":0,"description":"This page gives on overview of lab management in HUNT Cloud."},"headers":[],"relativePath":"administer-science/start-here/labs.md","filePath":"administer-science/start-here/labs.md"}'),s={name:"administer-science/start-here/labs.md"};function n(i,e,l,h,c,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="about-your-lab" tabindex="-1">About your lab <a class="header-anchor" href="#about-your-lab" aria-label="Permalink to &quot;About your lab&quot;">​</a></h1><p><strong>The digital lab is where you store and analyze your data and collaborate with your team.</strong></p><nav class="table-of-contents"><ul><li><a href="#machines">Machines</a></li><li><a href="#storage">Storage</a></li><li><a href="#backup">Backup</a></li></ul></nav><p>Technically, your lab is a virtual machine that runs on a server in one of our data centers. This virtual machine contains resources for data storage and computation, as well as security configurations and user management controls.</p><p>Your scientists, that we call &quot;lab users&quot;, gets their own workbench and personal folders. Principally all resources in your lab gets shared among your team, both computing power and storage. Your resources are dedicated to your lab, so you -not- access computing or storage resources from other labs in HUNT Cloud.</p><h3 id="machines" tabindex="-1">Machines <a class="header-anchor" href="#machines" aria-label="Permalink to &quot;Machines&quot;">​</a></h3><p>By default, your lab consist of two machines, an entry machine and a home machine. You can add more machine if you like.</p><p>The entry machine is a machine that we have set up to control the security and access to your lab. Your team has to pass this machine to enter your lab. However, they should only meet this machine during their user onboarding process.</p><p>The advantages of the entry machine is that we manage and maintain the security in your lab, including machine restarts, without affecting your scientific analysis that runs inside your lab.</p><p>The home machine is where most of the fun happens. This is the machine that is the home of your default storage, and most of your analysis tools, including your users&#39; lab benches (Workbench).</p><h3 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><p>By default, the home machine in your lab have three storage volumes that are reachable for all of your team:</p><ul><li><p><strong>Work volume.</strong> This is where you run your experiments. Place your scripts and code and do your work here. The directories for Workbench, licensed software (Matlab, Stata) and database directories are also stored here. Data saved here can be restored for 30 days.</p></li><li><p><strong>Archive volume</strong>. This is where you store your files that don&#39;t change that much, for example your data and analysis results. Data saved here can be restored for 30 days.</p></li><li><p><strong>Scratch volume</strong>. Scratch is designed for temporary data that gets generated when you run your scripts and analysis. This volume do -not- hold backup/restore.</p></li></ul><h3 id="backup" tabindex="-1">Backup <a class="header-anchor" href="#backup" aria-label="Permalink to &quot;Backup&quot;">​</a></h3><p>Both work and archive holds nightly backups, that we call restore, for 30 days. This means that you are able to restore data yourself in cases of accidental deletions and accidental overwrites. &#39;</p><p>Keep in mind that the restore function occupy a full duplicate copy of your data when you plan for your storage sizes. To illustrate, you will need at least 2TB of storage if you plan to store 1 TB of research data.</p><p>You can turn off the restore function if you don&#39;t need the additional safety measure.</p>',17)])])}const p=a(s,[["render",n]]);export{m as __pageData,p as default};
